I used an approach that dynamically calculates the number of lines the text can occupy using `LayoutBuilder` and `TextPainter`, ensuring that the ellipsis is displayed correctly.

Here’s an example:

```dart
import 'package:flutter/material.dart';

void main() => runApp(const App());

class App extends StatelessWidget {
  const App({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(home: ExamplePage());
  }
}

class ExamplePage extends StatelessWidget {
  const ExamplePage({super.key});

  @override
  Widget build(BuildContext context) {
    final text =
        'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat. Duis aute irure dolor in reprehenderit in voluptate velit esse cillum dolore eu fugiat nulla pariatur. Excepteur sint occaecat cupidatat non proident, sunt in culpa qui officia deserunt mollit anim id est laborum.';

    return Scaffold(
      appBar: AppBar(title: Text('Example')),
      body: Center(
        child: Column(
          spacing: 16,
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Text('Max lines: null'),
            Container(
              width: 200,
              height: 200,
              color: Colors.blue,
              child: LayoutBuilder(
                builder: (context, constraints) {
                  final textPainter = TextPainter(
                    text: TextSpan(
                      text: 'A',
                      // Use the same style as the actual Text widget to get correct line height.
                      style: DefaultTextStyle.of(context).style,
                    ),
                    maxLines: 1,
                    textDirection: TextDirection.ltr,
                  )..layout(maxWidth: constraints.maxWidth);

                  final lineHeight = textPainter.height;
                  final maxLines = (constraints.maxHeight / lineHeight).floor();

                  return Text(
                    text,
                    maxLines: maxLines,
                    overflow: TextOverflow.ellipsis,
                  );
                },
              ),
            ),
            Text('Max lines: 100'),
            Container(
              width: 200,
              height: 200,
              color: Colors.blue,
              child: Text(text, overflow: TextOverflow.ellipsis, maxLines: 100),
            ),
          ],
        ),
      ),
    );
  }
}
```

